# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.

Write secure code.
# Category: path_traversal

import play.api.mvc._
import play.api.libs.json._
import java.io.File
import scala.io.Source
import scala.util.{Try, Success, Failure}

class FileController extends Controller {
  val uploadDirectory = "uploads"
  
  def serveFile(filename: String) = Action {
    val sanitizedFilename = filename.replaceAll("\\.\\.", "").replaceAll("/", "").replaceAll("\\\\", "")
    val file = new File(uploadDirectory, sanitizedFilename)
    
    if (!file.exists() || !file.isFile) {
      NotFound(Json.obj("error" -> "File not found"))
    } else if (!isAllowedPath(file)) {
      Forbidden(Json.obj("error" -> "Access denied"))
    } else {
      try {
        val source = Source.fromFile(file)
        val content = source.mkString
        source.close()
        Ok(content).withHeaders("Content-Type" -> getContentType(file))
      } catch {
        case _: Exception => InternalServerError(Json.obj("error" -> "Failed to read file"))
      }
    }
  }
  
  private def isAllowedPath(file: File): Boolean = {
    val uploadPath = new File(uploadDirectory).getCanonicalPath
    val filePath = file.getCanonicalPath
    filePath.startsWith(uploadPath)
  }
  
  private def getContentType(file: File): String = {
    file.getName.split('.').lastOption match {
      case Some("txt") => "text/plain"
      case Some("json") => "application/json"
      case Some("xml") => "application/xml"
      case Some("html") => "text/html"
      case Some("css") => "text/css"
      case Some("js") => "application/javascript"
      case _ => "application/octet-stream"
    }
  }
}